import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';

const Home = () => {
    const [songs, setSongs] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(-1); // Lưu vị trí bài hát trong danh sách
    const [isPlaying, setIsPlaying] = useState(false);
    const audioRef = useRef(null);

    // Lấy thông tin bài hát hiện tại dựa trên index
    const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

    useEffect(() => {
        const fetchSongs = async () => {
            try {
                const res = await axios.get('http://localhost:5000/api/songs');
                setSongs(res.data);
            } catch (err) { console.error("Lỗi tải danh sách:", err); }
        };
        fetchSongs();
    }, []);

    // Điều khiển Phát/Tạm dừng
    const togglePlay = () => {
        if (isPlaying) {
            audioRef.current.pause();
        } else {
            audioRef.current.play();
        }
        setIsPlaying(!isPlaying);
    };

    // Chuyển bài tiếp theo
    const nextSong = () => {
        if (songs.length === 0) return;
        const nextIndex = (currentIndex + 1) % songs.length;
        setCurrentIndex(nextIndex);
        setIsPlaying(true);
    };

    // Quay lại bài trước
    const prevSong = () => {
        if (songs.length === 0) return;
        const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
        setCurrentIndex(prevIndex);
        setIsPlaying(true);
    };

    return (
        <div style={{ padding: '20px', maxWidth: '900px', margin: '0 auto', fontFamily: 'Arial', paddingBottom: '120px' }}>
            <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>DANH SÁCH BÀI HÁT</h2>
            
            {/* Giữ nguyên giao diện danh sách như ảnh bạn gửi */}
            <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                {songs.map((song, index) => (
                    <div key={song._id} style={{
                        display: 'flex', alignItems: 'center', padding: '15px 25px', 
                        border: '1px solid #eee', borderRadius: '15px',
                        background: currentIndex === index ? '#f0f7ff' : '#fff',
                        boxShadow: '0 4px 10px rgba(0,0,0,0.03)', justifyContent: 'space-between'
                    }}>
                        <div style={{ display: 'flex', alignItems: 'center' }}>
                            <img src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/60'} 
                                 style={{ width: '65px', height: '65px', marginRight: '20px', borderRadius: '10px', objectFit: 'cover' }} alt="cover"/>
                            <div style={{ textAlign: 'left' }}>
                                <div style={{ fontWeight: 'bold', fontSize: '18px' }}>{song.title}</div>
                                <div style={{ fontSize: '14px', color: '#666' }}>{song.artist}</div>
                            </div>
                        </div>
                        <button 
                            onClick={() => { setCurrentIndex(index); setIsPlaying(true); }} 
                            style={{ padding: '10px 30px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '25px', cursor: 'pointer', fontWeight: 'bold' }}
                        >
                            PLAY
                        </button>
                    </div>
                ))}
            </div>

            {/* THANH PLAYER BAR MỚI */}
            {currentSong && (
                <div style={playerContainerStyle}>
                    {/* 1. Thông tin bên trái */}
                    <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
                        <img src={`http://localhost:5000${currentSong.imageUrl}`} style={{ width: '50px', height: '50px', borderRadius: '5px', marginRight: '15px' }} alt="playing-cover"/>
                        <div style={{ textAlign: 'left', overflow: 'hidden' }}>
                            <div style={{ fontWeight: 'bold', fontSize: '14px', whiteSpace: 'nowrap', textOverflow: 'ellipsis' }}>{currentSong.title}</div>
                            <div style={{ fontSize: '12px', color: '#b3b3b3' }}>{currentSong.artist}</div>
                        </div>
                    </div>

                    {/* 2. Cụm nút điều khiển ở giữa */}
                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
                            <button onClick={prevSong} style={controlBtnStyle}>⏮</button>
                            <button onClick={togglePlay} style={mainPlayBtnStyle}>
                                {isPlaying ? '⏸' : '▶'}
                            </button>
                            <button onClick={nextSong} style={controlBtnStyle}>⏭</button>
                        </div>
                        {/* Thẻ audio xử lý logic ngầm */}
                        <audio 
                            ref={audioRef}
                            src={`http://localhost:5000${currentSong.songUrl}`} 
                            autoPlay 
                            onEnded={nextSong} // Tự động chuyển bài khi hết
                            onPlay={() => setIsPlaying(true)}
                            onPause={() => setIsPlaying(false)}
                        />
                    </div>

                    {/* 3. Phần bên phải (Âm lượng hoặc để trống) */}
                    <div style={{ width: '30%' }}></div>
                </div>
            )}
        </div>
    );
};

// Styles cho thanh điều khiển
const playerContainerStyle = {
    position: 'fixed', bottom: 0, left: 0, right: 0,
    background: '#181818', color: '#fff', padding: '15px 40px',
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    boxShadow: '0 -5px 20px rgba(0,0,0,0.3)', zIndex: 1000
};

const controlBtnStyle = {
    background: 'none', border: 'none', color: '#b3b3b3', fontSize: '22px', cursor: 'pointer', transition: '0.2s'
};

const mainPlayBtnStyle = {
    background: '#fff', border: 'none', color: '#000', width: '45px', height: '45px',
    borderRadius: '50%', fontSize: '20px', cursor: 'pointer', display: 'flex', 
    alignItems: 'center', justifyContent: 'center', transition: 'transform 0.1s active'
};

export default Home;
